#include<bits/stdc++.h>
using namespace std;

const int N = 2e4 + 7;

int n, m, d[N], c, w[N];

vector<int> e[N];

void dfs(int u, int fa) {
	d[u] = w[u];
	for (int v : e[u]) {
    	if (v == fa) continue;
    	dfs(v, u);
    	d[u] += max(d[v], 0);
	}
}

int main()
{
	int ans = -2e9;
	cin >> n;
	for(int i = 1; i <= n; i++)
		cin >> w[i];
	for(int i = 1; i < n; i++)
	{
		int x, y;
		cin >> x >> y;
		e[x].push_back(y);
		e[y].push_back(x);
	}
	dfs(1, 0);
	for(int i = 1; i <= n; i++)
		ans = max(ans, d[i]);
	cout << ans;
}
